import{_ as s,o as e,c as i,ag as l}from"./chunks/framework.CTpQozEL.js";const k=JSON.parse('{"title":"Linux 서버","description":"Linux 서버 또는 클라우드 VPS에서 OpenClaw 실행 — 프로바이더 선택, 아키텍처, 튜닝","frontmatter":{"title":"Linux 서버","description":"Linux 서버 또는 클라우드 VPS에서 OpenClaw 실행 — 프로바이더 선택, 아키텍처, 튜닝"},"headers":[],"relativePath":"vps.md","filePath":"vps.md","lastUpdated":null}'),t={name:"vps.md"};function n(o,a,p,r,c,h){return e(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="linux-서버" tabindex="-1">Linux 서버 <a class="header-anchor" href="#linux-서버" aria-label="Permalink to &quot;Linux 서버&quot;">​</a></h1><p>모든 Linux 서버 또는 클라우드 VPS에서 OpenClaw 게이트웨이를 실행하십시오. 이 페이지는 프로바이더 선택을 도와주고, 클라우드 배포 방식을 설명하며, 어디서나 적용되는 일반 Linux 튜닝을 다룹니다.</p><h2 id="프로바이더-선택" tabindex="-1">프로바이더 선택 <a class="header-anchor" href="#프로바이더-선택" aria-label="Permalink to &quot;프로바이더 선택&quot;">​</a></h2><blockquote><p><strong>Railway</strong> <a href="/openclaw-docs-ko/install/railway">→</a> 원클릭, 브라우저 설정</p></blockquote><blockquote><p><strong>Northflank</strong> <a href="/openclaw-docs-ko/install/northflank">→</a> 원클릭, 브라우저 설정</p></blockquote><blockquote><p><strong>DigitalOcean</strong> <a href="/openclaw-docs-ko/install/digitalocean">→</a> 간단한 유료 VPS</p></blockquote><blockquote><p><strong>Oracle Cloud</strong> <a href="/openclaw-docs-ko/install/oracle">→</a> Always Free ARM 티어</p></blockquote><blockquote><p><strong>Fly.io</strong> <a href="/openclaw-docs-ko/install/fly">→</a> Fly Machines</p></blockquote><blockquote><p><strong>Hetzner</strong> <a href="/openclaw-docs-ko/install/hetzner">→</a> Hetzner VPS의 Docker</p></blockquote><blockquote><p><strong>GCP</strong> <a href="/openclaw-docs-ko/install/gcp">→</a> Compute Engine</p></blockquote><blockquote><p><strong>Azure</strong> <a href="/openclaw-docs-ko/install/azure">→</a> Linux VM</p></blockquote><blockquote><p><strong>exe.dev</strong> <a href="/openclaw-docs-ko/install/exe-dev">→</a> HTTPS 프록시가 있는 VM</p></blockquote><blockquote><p><strong>Raspberry Pi</strong> <a href="/openclaw-docs-ko/install/raspberry-pi">→</a> ARM 자체 호스팅</p></blockquote><p>**AWS (EC2 / Lightsail / 무료 티어)**도 잘 작동합니다. 커뮤니티 동영상 안내가 <a href="https://x.com/techfrenAJ/status/2014934471095812547" target="_blank" rel="noreferrer">x.com/techfrenAJ/status/2014934471095812547</a>에서 제공됩니다 (커뮤니티 리소스 -- 제공이 중단될 수 있습니다).</p><h2 id="클라우드-설정-작동-방식" tabindex="-1">클라우드 설정 작동 방식 <a class="header-anchor" href="#클라우드-설정-작동-방식" aria-label="Permalink to &quot;클라우드 설정 작동 방식&quot;">​</a></h2><ul><li><strong>게이트웨이는 VPS에서 실행</strong>되고 상태 + 워크스페이스를 소유합니다.</li><li><strong>Control UI</strong> 또는 <strong>Tailscale/SSH</strong>를 통해 노트북이나 휴대폰에서 연결합니다.</li><li>VPS를 진실 소스로 취급하고 상태 + 워크스페이스를 정기적으로 <strong>백업</strong>하십시오.</li><li>안전한 기본값: 게이트웨이를 루프백에 유지하고 SSH 터널 또는 Tailscale Serve를 통해 접근하십시오. <code>lan</code> 또는 <code>tailnet</code>에 바인드하는 경우 <code>gateway.auth.token</code> 또는 <code>gateway.auth.password</code>를 요구하십시오.</li></ul><p>관련 페이지: <a href="/openclaw-docs-ko/gateway/remote">게이트웨이 원격 접근</a>, <a href="/openclaw-docs-ko/platforms/">플랫폼 허브</a>.</p><h2 id="vps에서-공유-회사-에이전트" tabindex="-1">VPS에서 공유 회사 에이전트 <a class="header-anchor" href="#vps에서-공유-회사-에이전트" aria-label="Permalink to &quot;VPS에서 공유 회사 에이전트&quot;">​</a></h2><p>모든 사용자가 동일한 신뢰 경계에 있고 에이전트가 비즈니스 전용인 경우, 팀을 위한 단일 에이전트 실행은 유효한 설정입니다.</p><ul><li>전용 런타임(VPS/VM/컨테이너 + 전용 OS 사용자/계정)에 유지하십시오.</li><li>해당 런타임을 개인 Apple/Google 계정이나 개인 브라우저/패스워드 매니저 프로파일에 로그인하지 마십시오.</li><li>사용자들이 서로에게 적대적인 경우 게이트웨이/호스트/OS 사용자별로 분리하십시오.</li></ul><p>보안 모델 세부 사항: <a href="/openclaw-docs-ko/gateway/security/">보안</a>.</p><h2 id="vps와-함께-노드-사용" tabindex="-1">VPS와 함께 노드 사용 <a class="header-anchor" href="#vps와-함께-노드-사용" aria-label="Permalink to &quot;VPS와 함께 노드 사용&quot;">​</a></h2><p>클라우드에 게이트웨이를 유지하고 로컬 기기(Mac/iOS/Android/헤드리스)에 <strong>노드</strong>를 페어링할 수 있습니다. 노드는 게이트웨이가 클라우드에 있는 동안 로컬 화면/카메라/Canvas와 <code>system.run</code> 기능을 제공합니다.</p><p>문서: <a href="/openclaw-docs-ko/nodes/">노드</a>, <a href="/openclaw-docs-ko/cli/nodes">노드 CLI</a>.</p><h2 id="소형-vm-및-arm-호스트를-위한-시작-튜닝" tabindex="-1">소형 VM 및 ARM 호스트를 위한 시작 튜닝 <a class="header-anchor" href="#소형-vm-및-arm-호스트를-위한-시작-튜닝" aria-label="Permalink to &quot;소형 VM 및 ARM 호스트를 위한 시작 튜닝&quot;">​</a></h2><p>저전력 VM(또는 ARM 호스트)에서 CLI 명령어가 느리게 느껴지는 경우 Node의 모듈 컴파일 캐시를 활성화하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">grep</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -q</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;NODE_COMPILE_CACHE=/var/tmp/openclaw-compile-cache&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> ||</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> cat</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &gt;&gt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;&lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&#39;EOF&#39;</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">export NODE_COMPILE_CACHE=/var/tmp/openclaw-compile-cache</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">mkdir -p /var/tmp/openclaw-compile-cache</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">export OPENCLAW_NO_RESPAWN=1</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">EOF</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.bashrc</span></span></code></pre></div><ul><li><code>NODE_COMPILE_CACHE</code>는 반복 명령어 시작 시간을 개선합니다.</li><li><code>OPENCLAW_NO_RESPAWN=1</code>은 자체 재생성 경로의 추가 시작 오버헤드를 방지합니다.</li><li>첫 번째 명령어 실행이 캐시를 워밍하고, 이후 실행이 더 빠릅니다.</li><li>Raspberry Pi 특이 사항은 <a href="/openclaw-docs-ko/install/raspberry-pi">Raspberry Pi</a>를 참조하십시오.</li></ul><h3 id="systemd-튜닝-체크리스트-선택-사항" tabindex="-1">systemd 튜닝 체크리스트 (선택 사항) <a class="header-anchor" href="#systemd-튜닝-체크리스트-선택-사항" aria-label="Permalink to &quot;systemd 튜닝 체크리스트 (선택 사항)&quot;">​</a></h3><p><code>systemd</code>를 사용하는 VM 호스트의 경우 다음을 고려하십시오:</p><ul><li>안정적인 시작 경로를 위한 서비스 환경 추가: <ul><li><code>OPENCLAW_NO_RESPAWN=1</code></li><li><code>NODE_COMPILE_CACHE=/var/tmp/openclaw-compile-cache</code></li></ul></li><li>재시작 동작을 명시적으로 유지: <ul><li><code>Restart=always</code></li><li><code>RestartSec=2</code></li><li><code>TimeoutStartSec=90</code></li></ul></li><li>랜덤 I/O 콜드 스타트 페널티를 줄이기 위해 상태/캐시 경로에 SSD 기반 디스크를 선호하십시오.</li></ul><p>표준 <code>openclaw onboard --install-daemon</code> 경로의 경우 사용자 유닛을 편집하십시오:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">systemctl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> edit</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw-gateway.service</span></span></code></pre></div><div class="language-ini vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">ini</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">[Service]</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">OPENCLAW_NO_RESPAWN</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=1</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Environment</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">NODE_COMPILE_CACHE</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=/var/tmp/openclaw-compile-cache</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">Restart</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=always</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">RestartSec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=2</span></span>
<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">TimeoutStartSec</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">=90</span></span></code></pre></div><p>대신 의도적으로 시스템 유닛을 설치한 경우 <code>sudo systemctl edit openclaw-gateway.service</code>를 통해 <code>openclaw-gateway.service</code>를 편집하십시오.</p><p><code>Restart=</code> 정책이 자동화된 복구에 어떻게 도움이 되는지: <a href="https://www.redhat.com/en/blog/systemd-automate-recovery" target="_blank" rel="noreferrer">systemd는 서비스 복구를 자동화할 수 있습니다</a>.</p>`,36)])])}const g=s(t,[["render",n]]);export{k as __pageData,g as default};
